import{_ as t,o as a,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Segment (Export) Configuration","description":"","frontmatter":{"title":"Segment (Export) Configuration","slug":"segment-export-configuration"},"headers":[],"relativePath":"developer-hub/segment-export-configuration.md","filePath":"developer-hub/segment-export-configuration.md"}'),r={name:"developer-hub/segment-export-configuration.md"};function s(i,e,d,h,l,c){return a(),n("div",null,[...e[0]||(e[0]=[o(`<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>With a push of a button you can send your Branch data to your Segment dashboard, helping you to understand the power of Branch as an acquisition pathway, export your data to your entire suite of analytics tools and build custom audiences upon Branch data.</p><p>This documentation explains how to send <strong>Branch-referred events to Segment</strong>. If you&#39;d like to send Segment events to your Branch dashboard, please review the <a href="./segment-import.html">Segment Import integration</a>.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Once the Branch SDK is integrated into an app, Branch can detect which links are leading to installs, re-opens, and users&#39; actions. Enabling this integration and providing your Segment credentials will result in Branch automatically forwarding attributed events to Segment, in the exact format Segment expects.</p><h3 id="branch-events-sent-to-segment" tabindex="-1">Branch events sent to Segment <a class="header-anchor" href="#branch-events-sent-to-segment" aria-label="Permalink to &quot;Branch events sent to Segment&quot;">​</a></h3><p>Branch will send <em>attributed</em> <strong>installs</strong> and <strong>opens</strong>, as well as any <strong>content events</strong>, <strong>lifecycle events</strong>,<strong>custom events</strong> and <strong>commerce events</strong> you track with Branch. Non-referred events, clicks, web session starts, and pageviews will be excluded. Branch also sends all the data that is attached to the link that drove the referred event. This will allow you to analyze which campaigns, channels, etc. are helping you acquire and engage users.</p><table tabindex="0"><thead><tr><th>Property</th><th>Value</th><th>Sourced from</th><th>Example</th></tr></thead><tbody><tr><td><code>event</code></td><td>Branch event</td><td>event name</td><td>branch_OPEN</td></tr><tr><td><code>event_id</code></td><td>Unique ID for the event</td><td>Branch event ID</td><td>469939270182891107</td></tr><tr><td><code>properties</code></td><td>Branch Link Data Dictionary</td><td>Last Attributed Touch Data for the link to which the event was attributed</td><td>&quot;campaign&quot;: &quot;Segment test&quot;, &quot;channel&quot;: &quot;Slack&quot;</td></tr><tr><td><code>device_info</code></td><td>Device Data, like OS</td><td>Branch User Data for the device</td><td>&quot;os&quot;: &quot;ANDROID&quot;</td></tr><tr><td><code>anonymousId</code></td><td>Segment Anonymous ID</td><td>Segment SDK provided Anonymous ID</td><td>12356</td></tr><tr><td><code>IP</code></td><td>IP of the event</td><td>Device</td><td>192.82.115.928</td></tr></tbody></table><p>All of the above properties are received as flat <em>properties[key]</em>, even though some are stored as dictionaries in Branch. They are grouped in our documentation for legibility.</p><div class="warning custom-block"><p class="custom-block-title">WebSDK events not supported</p><p>We do not support Segment export for Branch WebSDK events</p></div><h2 id="what-does-it-look-like" tabindex="-1">What does it look like? <a class="header-anchor" href="#what-does-it-look-like" aria-label="Permalink to &quot;What does it look like?&quot;">​</a></h2><p>Branch events will appear as an event prepended with <strong>branch_</strong> in your Segment debugger.</p><p>Additionally, individual events, such as those seen in Live View or visible when looking at People, will have Branch Link data included. Here&#39;s an example:</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Segment (export), you need to have completed the following:</p><ol><li>Admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Have the Advanced Data Feeds add-on enabled on your Branch account. Advanced Data Feeds can be included as an add-on to both the Engagement and Performance <a href="./packaging.html">products</a>.</li><li>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</li><li>Implement the Segment mobile SDK</li><li>Admin access to your Segment account.</li></ol><h2 id="enable-segment-export" tabindex="-1">Enable Segment (Export) <a class="header-anchor" href="#enable-segment-export" aria-label="Permalink to &quot;Enable Segment (Export)&quot;">​</a></h2><h2 id="_1-retrieve-your-segment-token" tabindex="-1">1. Retrieve your Segment Token <a class="header-anchor" href="#_1-retrieve-your-segment-token" aria-label="Permalink to &quot;1. Retrieve your Segment Token&quot;">​</a></h2><p>Find your Segment Token and enter it into the Branch Dashboard.</p><ol><li><p>Navigate to <a href="https://app.segment.com/" target="_blank" rel="noreferrer">https://app.segment.com</a> and log into the Dashboard.</p></li><li><p>In the dashboard, navigate to your desired Workspace.</p></li><li><p>In that Workspace, navigate to <strong>Sources</strong> and select the Source that has your app listed. Branch is not yet an independent Source, so Branch events appear within your app&#39;s Source.</p></li><li><p>Click through to <em>Settings &gt; API Keys</em></p></li><li><p>Copy your key and secret - you&#39;ll enter it into the Branch dashboard in a minute.</p></li></ol><h2 id="_2-enable-segment-export-in-branch" tabindex="-1">2. Enable Segment (Export) in Branch <a class="header-anchor" href="#_2-enable-segment-export-in-branch" aria-label="Permalink to &quot;2. Enable Segment (Export) in Branch&quot;">​</a></h2><ol><li>On the Branch Dashboard (dashboard.branch.io), navigate to the <a href="https://branch.dashboard.branch.io/data-feeds/integrations" target="_blank" rel="noreferrer">Integrations page</a>.</li><li>Search for Segment and click on the tile.</li><li>Enter your Segment Token under the &quot;Export&quot; section and hit <strong>Enable</strong>.</li></ol><h2 id="_3-configure-app" tabindex="-1">3. Configure App <a class="header-anchor" href="#_3-configure-app" aria-label="Permalink to &quot;3. Configure App&quot;">​</a></h2><p>Pass Segment Anonymous ID</p><p>When you&#39;re ready to send data through Branch, you&#39;ll need to make sure you pass through the configured Segment Anonymous ID the Branch SDKs. In order to do so, you&#39;ll ask the Segment SDK to provide you with the Segment Anonymous ID, and pass this value through <code>setRequestMetadataKey</code> on the Branch SDKs.</p><p>Here&#39;s a sample snippet showing this. <strong>NOTE</strong> you must set the correct key before calling <code>sessionBuilder()...init()</code>. You must also initialize the Segment SDK before setting the request metadata in the Branch SDK.</p><p><strong>iOS</strong></p><p>Inside <em>didFinishLaunchingWithOptions</em></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        Branch *branch = [Branch getInstance];</span></span>
<span class="line"><span>        [[Branch getInstance] setRequestMetadataKey:@&quot;$segment_anonymous_id&quot; value:[[SEGAnalytics sharedAnalytics] getAnonymousId]];</span></span></code></pre></div><p><strong>Swift</strong></p><p>Inside <em>didFinishLaunchingWithOptions</em></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        if let branch = Branch.getInstance() {</span></span>
<span class="line"><span>        branch.setRequestMetadataKey(&quot;$segment_anonymous_id&quot;, value:&quot;1234&quot; as NSObject!);</span></span>
<span class="line"><span>        }</span></span></code></pre></div><p><strong>Android</strong></p><p>Before you initialize in your Application#onCreate or Deep Link Activity&#39;s #onCreate.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        Branch.getInstance().setRequestMetadata(&quot;$segment_anonymous_id&quot;, com.segment.analytics.Analytics.with(this).getAnalyticsContext().traits().anonymousId());</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        Branch.sessionBuilder(this)...init();&quot;</span></span></code></pre></div><p>In the above snippet, <code>this</code> is the Activity context.</p><h2 id="_4-verify-data-sent" tabindex="-1">4. Verify Data Sent <a class="header-anchor" href="#_4-verify-data-sent" aria-label="Permalink to &quot;4. Verify Data Sent&quot;">​</a></h2><p>Once the above steps are complete, you are now ready to start launching campaigns. Branch-attributed conversions will be sent to Segment. To verify data is being sent from Branch to Segment, you can look at the Branch Dashboard&#39;s <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>webhook partner key</td><td>equals</td><td>di_segment</td></tr></tbody></table><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>How do I pass Segment Anonymous ID in React Native when configuring Segment Export?</summary><p>The Segment Anonymous ID can be passed with the React-Native plugin by following the methods below:</p><p>iOS (Inside didFinishLaunchingWithOptions):</p><p>RNBranch.setRequestMetadataKey(&quot;$segment_anonymous_id&quot;, &quot;value&quot;)</p><p>Android (Before you initialize in your Application#onCreate or Deep Link Activity&#39;s #onCreate):</p><p>RNBranchModule.setRequestMetadata(&quot;$segment_anonymous_id&quot;, &quot;value&quot;);</p></details>`,42)])])}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
